        this.attachFormSubmitListener();

        //alt y title de imagen title
        // ALT + TITLE + ARIA (accesibilidad)
        const addAccessibility = () => {
            let updated = false;

            // Logo
            const logo = document.querySelector(".image-title");
            if (logo && !logo.hasAttribute("alt")) {
                logo.setAttribute("alt", "Logo institucional del asistente virtual");
                logo.setAttribute("title", "Logo institucional del asistente virtual");
                updated = true;
            }

            const avatar = document.querySelector(".rcw-avatar");
            if (avatar && !avatar.hasAttribute("alt")) {
                avatar.setAttribute("alt", "Avatar del asistente virtual");
                avatar.setAttribute("title", "Avatar del asistente virtual");
                updated = true;
            }

            // Botón de formulario principal (MUI)
            const buttons = document.querySelectorAll("button");
            buttons.forEach((btn) => {
                const label = btn.innerText?.trim().toLowerCase();
                if (label === "enviar" && !btn.hasAttribute("aria-label")) {
                    btn.setAttribute("aria-label", "Enviar formulario para iniciar el chat");
                    btn.setAttribute("title", "Enviar formulario para iniciar el chat");
                    updated = true;
                }
            });

            // Botón de envío del widget (chat)
            const sendButton = document.querySelector(".rcw-send");
            if (sendButton && !sendButton.hasAttribute("aria-label")) {
                sendButton.setAttribute("aria-label", "Enviar mensaje");
                sendButton.setAttribute("title", "Enviar mensaje");
                updated = true;
            }

            return updated;
        };

        // Ejecutar y seguir intentando hasta que todo esté accesible
        if (!addAccessibility()) {
            let tries = 0;
            const interval = setInterval(() => {
                tries++;
                if (addAccessibility() || tries > 20) {
                    clearInterval(interval);
                }
            }, 500);
        }

        const inputs = document.querySelectorAll("form[name='chatReduxForm'] input, form[name='chatReduxForm'] select, form[name='chatReduxForm'] textarea");
