    attachFormSubmitListener() {
        const form = document.querySelector("form[name='chatReduxForm']");
        if (!form) return;

        // Evitar duplicar listeners si el componente se re-renderiza
        if (form.dataset.listenerAttached === "true") return;
        form.dataset.listenerAttached = "true";

        form.addEventListener("submit", (e) => {
            e.preventDefault();
            e.stopPropagation();

            const { reduxCompanyForm } = this.props;

            // ✅ Ejecuta la validación personalizada
            if (this.validations(reduxCompanyForm)) {
                console.log("✅ Validación completa, se puede enviar.");
                this.props.startConversation(reduxCompanyForm);
            } else {
                console.warn("❌ Validación fallida, formulario incompleto.");

                // 🔹 Marca los campos inválidos visualmente (opcional)
                const requiredFields = form.querySelectorAll("input[required], select[required], textarea[required]");
                requiredFields.forEach(field => {
                    if (!field.value.trim()) {
                        field.classList.add("input-error");
                        field.setAttribute("aria-invalid", "true");
                    } else {
                        field.classList.remove("input-error");
                        field.removeAttribute("aria-invalid");
                    }
                });
            }
        });
    }

    doSubmit = (value) => {
        const { startConversation } = this.props
        if (validateCaptcha(value) === true) {
            //alert('Captcha Matched');
            loadCaptchaEnginge(6);
            this.setState({
                valueCaptcha: "",
                captchaValidado: true,
            })
            startConversation({ subject: "hola", captcha: true })
        }
        else {
            //alert('Captcha Does Not Match');
            this.setState({
                valueCaptcha: "",
                captchaValidado: false,
                errorCaptchaInvalido: true
            })
        }
    };

